import time
import threading

rate_limits = {}
lock = threading.Lock()

def check_rate_limit(client_ip, max_requests=100, window_seconds=60):
    now = time.time()
    if client_ip not in rate_limits:
        rate_limits[client_ip] = []

    rate_limits[client_ip].append(now)

    # Remove old entries
    rate_limits[client_ip] = [t for t in rate_limits[client_ip] if now - t < window_seconds]

    if len(rate_limits[client_ip]) > max_requests:
        return False
    return True

def get_remaining(client_ip, max_requests=100, window_seconds=60):
    now = time.time()
    if client_ip not in rate_limits:
        return max_requests
    count = len([t for t in rate_limits[client_ip] if now - t < window_seconds])
    return max_requests - count

def reset_client(client_ip):
    if client_ip in rate_limits:
        del rate_limits[client_ip]

def reset_all():
    global rate_limits
    rate_limits = {}

def get_all_clients():
    return list(rate_limits.keys())
